            "gl_FragColor.xyz = gl_FragColor.xyz * ( totalDiffuse + ambientLightColor * uAmbientColor ) + totalSpecular;",
            "#endif",
            "if ( enableReflection ) {",
            "vec3 vReflect;",
            "vec3 cameraToVertex = normalize( vWorldPosition - cameraPosition );",
